import{M as e,d as t,h as n}from"./chunks/runtime-core.esm-bundler.Di_optew.js";import{t as r}from"./chunks/plugin-vue_export-helper.B_ZXV7eh.js";var i=JSON.parse(`{"title":"Vite 7.0 is out!","description":"","frontmatter":{"title":"Vite 7.0 is out!","author":{"name":"The Vite Team"},"date":"2025-06-24T00:00:00.000Z","sidebar":false,"head":[["meta",{"property":"og:type","content":"website"}],["meta",{"property":"og:title","content":"Announcing Vite 7"}],["meta",{"property":"og:image","content":"https://vite.dev/og-image-announcing-vite7.webp"}],["meta",{"property":"og:url","content":"https://vite.dev/blog/announcing-vite7"}],["meta",{"property":"og:description","content":"Vite 7 Release Announcement"}],["meta",{"name":"twitter:card","content":"summary_large_image"}]]},"headers":[],"relativePath":"blog/announcing-vite7.md","filePath":"blog/announcing-vite7.md"}`),a={name:`blog/announcing-vite7.md`};function o(r,i,a,o,s,c){return e(),t(`div`,null,[...i[0]||=[n(`<h1 id="vite-7-0-is-out" tabindex="-1">Vite 7.0 is out! <a class="header-anchor" href="#vite-7-0-is-out" aria-label="Permalink to “Vite 7.0 is out!”">​</a></h1><p><em>June 24, 2025</em></p><p><img src="/og-image-announcing-vite7.webp" alt="Vite 7 Announcement Cover Image" width="2400" height="1200"></p><p>We&#39;re happy to share the release of Vite 7! It has been 5 years since Evan You sent the first commit to the Vite repo, and nobody could have predicted how much the frontend ecosystem would change since then. Most modern frontend frameworks and tools are now working together, building on top of Vite&#39;s shared infrastructure. And they can innovate at a faster pace by sharing at a higher level. Vite is now being downloaded 31 million times a week, with a 14 million increase in the last seven months since the previous major release.</p><p>This year, we&#39;re making several big steps. To start with, <a href="https://viteconf.org" target="_blank" rel="noreferrer">ViteConf</a> is going to be in person! The Vite Ecosystem will gather in Amsterdam on October 9-10! Organized by <a href="https://jsworldconference.com/" target="_blank" rel="noreferrer">JSWorld</a> in partnership with <a href="https://bolt.new" target="_blank" rel="noreferrer">Bolt</a>, <a href="https://voidzero.dev" target="_blank" rel="noreferrer">VoidZero</a>, and the Vite Core Team! We had three incredible <a href="https://www.youtube.com/@viteconf/playlists" target="_blank" rel="noreferrer">ViteConf online editions</a>, and we can&#39;t wait to meet in real life. Check out the speakers and get your ticket at the <a href="https://viteconf.org" target="_blank" rel="noreferrer">ViteConf site</a>!</p><p>And <a href="https://voidzero.dev/posts/announcing-voidzero-inc" target="_blank" rel="noreferrer">VoidZero</a> continues to make significant strides in its mission to build an open source unified development toolchain for the JavaScript ecosystem. Over the last year, the VoidZero team has been working on <a href="https://rolldown.rs/" target="_blank" rel="noreferrer">Rolldown</a>, a Rust-based next-generation bundler, as part of a broader effort to modernize Vite&#39;s core. You can try out the Rolldown-powered Vite today by using the <code>rolldown-vite</code> package instead of the default <code>vite</code> package. It is a drop-in replacement, as Rolldown will become the default bundler for Vite in the future. Switching should reduce your build time, especially for larger projects. Read more at the <a href="https://voidzero.dev/posts/announcing-rolldown-vite" target="_blank" rel="noreferrer">Rolldown-vite announcement blog post</a> and our <a href="https://vite.dev/rolldown" target="_blank" rel="noreferrer">migration guide</a>.</p><p>Through a partnership between VoidZero and <a href="https://nuxtlabs.com/" target="_blank" rel="noreferrer">NuxtLabs</a>, Anthony Fu is working on creating Vite DevTools. They will offer deeper and more insightful debugging and analysis for all Vite-based projects and frameworks. You can read more on the <a href="https://voidzero.dev/posts/voidzero-nuxtlabs-vite-devtools" target="_blank" rel="noreferrer">VoidZero and NuxtLabs join forces on Vite Devtools blog post</a>.</p><p>Quick links:</p><ul><li><a href="/">Docs</a></li><li>New Translation: <a href="https://fa.vite.dev/" target="_blank" rel="noreferrer">فارسی</a></li><li>Other Translations: <a href="https://cn.vite.dev/" target="_blank" rel="noreferrer">简体中文</a>, <a href="https://ja.vite.dev/" target="_blank" rel="noreferrer">日本語</a>, <a href="https://es.vite.dev/" target="_blank" rel="noreferrer">Español</a>, <a href="https://pt.vite.dev/" target="_blank" rel="noreferrer">Português</a>, <a href="https://ko.vite.dev/" target="_blank" rel="noreferrer">한국어</a>, <a href="https://de.vite.dev/" target="_blank" rel="noreferrer">Deutsch</a></li><li><a href="/guide/migration">Migration Guide</a></li><li><a href="https://github.com/vitejs/vite/blob/main/packages/vite/CHANGELOG.md" target="_blank" rel="noreferrer">GitHub Changelog</a></li></ul><p>Play online with Vite 7 using <a href="https://vite.new" target="_blank" rel="noreferrer">vite.new</a> or scaffold a Vite app locally with your preferred framework running <code>pnpm create vite</code>. Check out the <a href="/guide/">Getting Started Guide</a> for more information.</p><p>We invite you to help us improve Vite (joining the more than <a href="https://github.com/vitejs/vite/graphs/contributors" target="_blank" rel="noreferrer">1.1K contributors to Vite Core</a>), our dependencies, or plugins and projects in the ecosystem. Learn more at our <a href="https://github.com/vitejs/vite/blob/main/CONTRIBUTING.md" target="_blank" rel="noreferrer">Contributing Guide</a>. A good way to get started is by <a href="https://github.com/vitejs/vite/issues" target="_blank" rel="noreferrer">triaging issues</a>, <a href="https://github.com/vitejs/vite/pulls" target="_blank" rel="noreferrer">reviewing PRs</a>, sending tests PRs based on open issues, and supporting others in <a href="https://github.com/vitejs/vite/discussions" target="_blank" rel="noreferrer">Discussions</a> or Vite Land&#39;s <a href="https://discord.com/channels/804011606160703521/1019670660856942652" target="_blank" rel="noreferrer">help forum</a>. If you have questions, join our <a href="https://chat.vite.dev" target="_blank" rel="noreferrer">Discord community</a> and talk to us in the <a href="https://discord.com/channels/804011606160703521/804439875226173480" target="_blank" rel="noreferrer">#contributing channel</a>.</p><p>Stay updated and connect with others building on top of Vite by following us on <a href="https://bsky.app/profile/vite.dev" target="_blank" rel="noreferrer">Bluesky</a>, <a href="https://twitter.com/vite_js" target="_blank" rel="noreferrer">X</a>, or <a href="https://webtoo.ls/@vite" target="_blank" rel="noreferrer">Mastodon</a>.</p><h2 id="node-js-support" tabindex="-1">Node.js Support <a class="header-anchor" href="#node-js-support" aria-label="Permalink to “Node.js Support”">​</a></h2><p>Vite now requires Node.js 20.19+, 22.12+. We have dropped Node.js 18, now that it has reached its <a href="https://endoflife.date/nodejs" target="_blank" rel="noreferrer">EOL</a> at the end of April 2025.</p><p>We require these new ranges so Node.js supports <code>require(esm)</code> without a flag. This allows us to distribute Vite 7.0 as ESM only without preventing the Vite JavaScript API from being required by CJS modules. Check out Anthony Fu&#39;s <a href="https://antfu.me/posts/move-on-to-esm-only" target="_blank" rel="noreferrer">Move on to ESM-only</a> for a detailed review of the current state of ESM in the ecosystem.</p><h2 id="default-browser-target-changed-to-baseline-widely-available" tabindex="-1">Default Browser Target Changed to Baseline Widely Available <a class="header-anchor" href="#default-browser-target-changed-to-baseline-widely-available" aria-label="Permalink to “Default Browser Target Changed to Baseline Widely Available”">​</a></h2><p><a href="https://web-platform-dx.github.io/web-features/" target="_blank" rel="noreferrer">Baseline</a> gives us clear information about which web platform features work across their core browser set today. Baseline Widely Available indicates the feature is well-established and works across many devices and browser versions, being available across browsers for at least 30 months.</p><p>In Vite 7, the default browser target is changing from <code>&#39;modules&#39;</code> to a new default: <code>&#39;baseline-widely-available&#39;</code>. The set of browsers will be updated on each major to match the list of minimum browser versions compatible with Baseline Widely available features. The default browser value of <code>build.target</code> is changing in Vite 7.0:</p><ul><li>Chrome 87 → 107</li><li>Edge 88 → 107</li><li>Firefox 78 → 104</li><li>Safari 14.0 → 16.0</li></ul><p>This change adds predictability to the default browser target for future releases.</p><h2 id="vitest" tabindex="-1">Vitest <a class="header-anchor" href="#vitest" aria-label="Permalink to “Vitest”">​</a></h2><p>For Vitest users, Vite 7.0 is supported from Vitest 3.2. You can read more about how the Vitest team keeps improving Vite testing story in the <a href="https://vitest.dev/blog/vitest-3-2.html" target="_blank" rel="noreferrer">Vitest 3.2 release blog post</a>.</p><h2 id="environment-api" tabindex="-1">Environment API <a class="header-anchor" href="#environment-api" aria-label="Permalink to “Environment API”">​</a></h2><p>Vite 6 was the most significant major release since Vite 2, adding new capabilities with the <a href="https://vite.dev/blog/announcing-vite6.html#experimental-environment-api" target="_blank" rel="noreferrer">new experimental Environment API</a>. We are keeping the new APIs as experimental while the ecosystem reviews how the new APIs fit on their projects and provide feedback. If you&#39;re building on top of Vite, we encourage you to test the new APIs and reach out to us in the <a href="https://github.com/vitejs/vite/discussions/16358" target="_blank" rel="noreferrer">open Feedback discussion here</a>.</p><p>In Vite 7, we added a new <code>buildApp</code> hook to let plugins coordinate the building of environments. Read more in the <a href="/guide/api-environment-frameworks.html#environments-during-build">Environment API for Frameworks guide</a>.</p><p>We want to thank the teams that have been testing the new APIs and helping us stabilize the new features. The Cloudflare team, for example, announced the 1.0 release of their Cloudflare Vite plugin, as well as official support for React Router v7. Their plugin shows the potential of Environment API for runtime providers. Learn more about their approach and future steps at <a href="https://blog.cloudflare.com/introducing-the-cloudflare-vite-plugin/" target="_blank" rel="noreferrer">&quot;Just use Vite”… with the Workers runtime</a>.</p><h2 id="migrating-to-vite-7" tabindex="-1">Migrating to Vite 7 <a class="header-anchor" href="#migrating-to-vite-7" aria-label="Permalink to “Migrating to Vite 7”">​</a></h2><p>Vite 7 should be a smooth update from Vite 6. We&#39;re removing already deprecated features, like Sass legacy API support and the <code>splitVendorChunkPlugin</code> that shouldn&#39;t affect your projects. We still suggest you review the <a href="/guide/migration">detailed Migration Guide</a> before upgrading.</p><p>The complete list of changes is at the <a href="https://github.com/vitejs/vite/blob/main/packages/vite/CHANGELOG.md" target="_blank" rel="noreferrer">Vite 7 Changelog</a>.</p><h2 id="acknowledgments" tabindex="-1">Acknowledgments <a class="header-anchor" href="#acknowledgments" aria-label="Permalink to “Acknowledgments”">​</a></h2><p>Vite 7 was crafted by the <a href="/team">Vite Team</a> with the help of the wide community of contributors, downstream maintainers, plugin authors. A special shout-out to <a href="https://github.com/sapphi-red" target="_blank" rel="noreferrer">sapphi-red</a> for his remarkable work on <code>rolldown-vite</code> and this release. Vite is brought to you by <a href="https://voidzero.dev" target="_blank" rel="noreferrer">VoidZero</a>, in partnership with <a href="https://bolt.new/" target="_blank" rel="noreferrer">Bolt</a> and <a href="https://nuxtlabs.com/" target="_blank" rel="noreferrer">Nuxt Labs</a>. We also want to thank our sponsors on <a href="https://github.com/sponsors/vitejs" target="_blank" rel="noreferrer">Vite&#39;s GitHub Sponsors</a> and <a href="https://opencollective.com/vite" target="_blank" rel="noreferrer">Vite&#39;s Open Collective</a>.</p>`,31)]])}var s=r(a,[[`render`,o]]);export{i as __pageData,s as default};